from __future__ import annotations

import argparse
import os
import shutil
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import List, Optional


@dataclass
class RunResult:
    code: int


def eprint(*args: object) -> None:
    print(*args, file=sys.stderr)


def run(cmd: List[str], cwd: Optional[Path] = None, env: Optional[dict] = None) -> RunResult:
    eprint("+", " ".join(cmd))
    p = subprocess.run(cmd, cwd=str(cwd) if cwd else None, env=env)
    return RunResult(code=p.returncode)


def which_or_exit(name: str) -> str:
    path = shutil.which(name)
    if not path:
        eprint(f"ERROR: '{name}' not found on PATH. Install it and retry.")
        raise SystemExit(2)
    return path


def ensure_parent_dir(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def pip_compile(
    in_file: Path,
    out_file: Path,
    *,
    hashes: bool,
    upgrade: bool,
    upgrade_package: Optional[str],
    python_executable: Optional[str],
    extra_args: List[str],
) -> int:
    which_or_exit("pip-compile")

    ensure_parent_dir(out_file)

    cmd = ["pip-compile", str(in_file), "--output-file", str(out_file)]
    if hashes:
        cmd.append("--generate-hashes")
    cmd += ["--resolver", "backtracking"]
    cmd += ["--strip-extras"]
    cmd += ["--allow-unsafe"]

    if upgrade:
        cmd.append("--upgrade")
    if upgrade_package:
        cmd += ["--upgrade-package", upgrade_package]

    if python_executable:
        cmd += ["--python-executable", python_executable]

    cmd += extra_args

    return run(cmd).code


def pip_sync(requirement_files: List[Path], *, extra_args: List[str]) -> int:
    which_or_exit("pip-sync")

    cmd = ["pip-sync"] + [str(p) for p in requirement_files] + extra_args
    return run(cmd).code


def poetry_lock(*, no_update: bool) -> int:
    which_or_exit("poetry")
    cmd = ["poetry", "lock"]
    if no_update:
        cmd.append("--no-update")
    return run(cmd).code


def poetry_update(package: Optional[str], *, extra_args: List[str]) -> int:
    which_or_exit("poetry")
    cmd = ["poetry", "update"]
    if package:
        cmd.append(package)
    cmd += extra_args
    return run(cmd).code


def poetry_install(*, sync: bool, only: Optional[str], with_groups: Optional[str], without_groups: Optional[str]) -> int:
    which_or_exit("poetry")
    cmd = ["poetry", "install"]
    if sync:
        cmd.append("--sync")
    if only:
        cmd += ["--only", only]
    if with_groups:
        cmd += ["--with", with_groups]
    if without_groups:
        cmd += ["--without", without_groups]
    return run(cmd).code


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(
        prog="deps_lock.py",
        description="Documentation + helper for managing pip-tools (requirements with hashes) or Poetry lock files.",
        formatter_class=argparse.RawTextHelpFormatter,
    )
    sub = p.add_subparsers(dest="cmd", required=True)

    c = sub.add_parser(
        "pip-compile",
        help="Compile a requirements.in into a locked requirements.txt (optionally with hashes).",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    c.add_argument("--in", dest="in_file", required=True, type=Path, help="Input requirements.in path.")
    c.add_argument("--out", dest="out_file", required=True, type=Path, help="Output requirements.txt path.")
    c.add_argument("--hashes", action="store_true", help="Generate hashes (recommended for production).")
    c.add_argument("--upgrade", action="store_true", help="Upgrade all packages within constraints.")
    c.add_argument("--upgrade-package", dest="upgrade_package", default=None, help="Upgrade a single package.")
    c.add_argument(
        "--python-executable",
        dest="python_executable",
        default=None,
        help="Python interpreter to resolve for (helps when multiple Pythons exist).",
    )
    c.add_argument(
        "--extra-arg",
        dest="extra_args",
        action="append",
        default=[],
        help="Additional argument to pass through to pip-compile (repeatable).",
    )

    s = sub.add_parser(
        "pip-sync",
        help="Sync the current environment to match one or more locked requirements files exactly.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    s.add_argument(
        "--req",
        dest="reqs",
        action="append",
        type=Path,
        required=True,
        help="Locked requirements file(s) to sync to (repeatable).",
    )
    s.add_argument(
        "--extra-arg",
        dest="extra_args",
        action="append",
        default=[],
        help="Additional argument to pass through to pip-sync (repeatable).",
    )

    pl = sub.add_parser(
        "poetry-lock",
        help="Generate/update poetry.lock (resolution).",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    pl.add_argument("--no-update", action="store_true", help="Recompute lock without updating versions (verification).")

    pu = sub.add_parser(
        "poetry-update",
        help="Update dependencies and poetry.lock within constraints.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    pu.add_argument("--package", default=None, help="Update a single package.")
    pu.add_argument(
        "--extra-arg",
        dest="extra_args",
        action="append",
        default=[],
        help="Additional argument to pass through to poetry update (repeatable).",
    )

    pi = sub.add_parser(
        "poetry-install",
        help="Install from poetry.lock deterministically.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    pi.add_argument("--sync", action="store_true", help="Remove packages not present in lock (recommended in CI).")
    pi.add_argument("--only", default=None, help="Only install dependency groups (e.g. 'main').")
    pi.add_argument("--with", dest="with_groups", default=None, help="Install additional groups.")
    pi.add_argument("--without", dest="without_groups", default=None, help="Exclude groups.")

    doc = sub.add_parser(
        "print-docs",
        help="Print the built-in documentation.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )

    return p


def main(argv: List[str]) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)

    if args.cmd == "print-docs":
        print(__doc__.strip() + "\n")
        return 0

    if args.cmd == "pip-compile":
        return pip_compile(
            in_file=args.in_file,
            out_file=args.out_file,
            hashes=bool(args.hashes),
            upgrade=bool(args.upgrade),
            upgrade_package=args.upgrade_package,
            python_executable=args.python_executable,
            extra_args=args.extra_args,
        )

    if args.cmd == "pip-sync":
        return pip_sync(requirement_files=args.reqs, extra_args=args.extra_args)

    if args.cmd == "poetry-lock":
        return poetry_lock(no_update=bool(args.no_update))

    if args.cmd == "poetry-update":
        return poetry_update(package=args.package, extra_args=args.extra_args)

    if args.cmd == "poetry-install":
        return poetry_install(
            sync=bool(args.sync),
            only=args.only,
            with_groups=args.with_groups,
            without_groups=args.without_groups,
        )

    eprint(f"ERROR: Unknown command {args.cmd!r}")
    return 2


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))